from flask import Flask, redirect, request, session, url_for
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'
client_id = 'your_client_id'
client_secret = 'your_client_secret'
redirect_uri = 'http://localhost:5000/callback'
authorization_endpoint = 'https://provider.com/authorize'
token_endpoint = 'https://provider.com/token'
userinfo_endpoint = 'https://provider.com/userinfo'

@app.route('/')
def home():
    return 'Welcome to the Flask OpenID Connect App! <a href="/login">Login</a>'

@app.route('/login')
def login():
    params = {
        'response_type': 'code',
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': 'openid profile',
        'state': 'random_state_string'
    }
    url = f"{authorization_endpoint}?{requests.compat.urlencode(params)}"
    return redirect(url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(token_endpoint, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': client_id,
        'client_secret': client_secret
    })
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    decoded_token = jwt.decode(id_token, options={"verify_signature": False})
    session['user'] = decoded_token
    return redirect(url_for('profile'))

@app.route('/profile')
def profile():
    user = session.get('user')
    if user:
        return f"Hello, {user['name']}! <a href='/logout'>Logout</a>"
    return redirect(url_for('home'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)